#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_M 200
#define MAX_N 200000
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, K, N;
        scanf("%d %d %d", &M, &K, &N);
        int graph[MAX_M][MAX_M] = {{0}};
        for (int i = 0; i < K; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            graph[x-1][y-1] = 1;
        }
        // Compute transitive closure
        for (int k = 0; k < M; k++) {
            for (int i = 0; i < M; i++) {
                for (int j = 0; j < M; j++) {
                    if (graph[i][k] && graph[k][j]) {
                        graph[i][j] = 1;
                    }
                }
            }
        }
        int word[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &word[i]);
        }
        // Perform topological sort
        int sorted[N];
        int count = 0;
        for (int i = 0; i < N; i++) {
            int found = 0;
            for (int j = 0; j < count; j++) {
                if (graph[sorted[j]-1][word[i]-1]) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                sorted[count++] = word[i];
            }
        }
        if (count != N) {
            printf("-1\n");
        } else {
            // Use BFS to find minimum number of transformations
            int queue[N];
            int visited[N] = {0};
            int distance[N] = {0};
            int head = 0, tail = 0;
            for (int i = 0; i < N; i++) {
                if (word[i] != sorted[i]) {
                    queue[tail++] = i;
                    visited[i] = 1;
                }
            }
            while (head < tail) {
                int current = queue[head++];
                for (int i = 0; i < N; i++) {
                    if (!visited[i] && graph[word[current]-1][word[i]-1]) {
                        queue[tail++] = i;
                        visited[i] = 1;
                        distance[i] = distance[current] + 1;
                    }
                }
            }
            int min_distance = 0;
            for (int i = 0; i < N; i++) {
                min_distance += distance[i];
            }
            printf("%d\n", min_distance);
        }
    }
    return 0;
}

