                // Use BFS to find minimum number of transformations
                Queue<Integer> q = new LinkedList<>();
                int[] visited = new int[N];
                int[] distance = new int[N];
                for (int i = 0; i < N; i++) {
                    if (word[i] != sorted[i]) {
                        q.add(i);
                        visited[i] = 1;
                    }
                }
                while (!q.isEmpty()) {
                    int current = q.poll();
                    for (int i = 0; i < N; i++) {
                        if (visited[i] == 0 && graph[word[current] - 1][word[i] - 1] == 1) {
                            q.add(i);
                            visited[i] = 1;
                            distance[i] = distance[current] + 1;
                        }
                    }
                }
                int min_distance = 0;
                for (int i = 0; i < N; i++) {
                    min_distance += distance[i];
                }
                System.out.println(min_distance);
            }
        }
    }
}

